// Provide deterministic sample records for manual testing.
return [
  {
    json: {
      items: [
        {
          source: 'rss',
          title: 'AI Agent 與工作流',
          url: 'https://example.com/posts/ai-agent',
          content: 'AI Agent 不只生成文字，也應根據工具結果決定下一步。',
          language: 'zh-TW',
          publishedAt: '2026-07-16T00:00:00.000Z'
        },
        {
          source: 'rss',
          title: 'AI Agent 與工作流（重複）',
          url: 'https://example.com/posts/ai-agent',
          content: '這是一筆相同 URL 的重複資料。',
          language: 'zh-TW',
          publishedAt: '2026-07-16T00:00:00.000Z'
        }
      ]
    }
  }
];

// Normalize webhook, RSS, Telegram, or manual payloads into one content shape.
const input = $input.first().json;
const body = input.body ?? input;
const candidates = Array.isArray(body) ? body : Array.isArray(body.items) ? body.items : [body];

const normalized = candidates.map((item, index) => {
  const url = String(item.url ?? item.link ?? item.tweet_url ?? '').trim();
  const title = String(item.title ?? item.name ?? '').trim();
  const content = String(item.content ?? item.text ?? item.description ?? item.body ?? '').trim();
  const source = String(item.source ?? (item.tweet_url ? 'x' : 'webhook')).toLowerCase();
  const language = String(item.language ?? 'zh-TW');
  const publishedAt = item.publishedAt ?? item.pubDate ?? item.isoDate ?? null;

  return {
    json: {
      id: String(item.id ?? `${source}:${url || index}`),
      source,
      title,
      url,
      language,
      content,
      images: Array.isArray(item.images) ? item.images : [],
      tags: Array.isArray(item.tags) ? item.tags : [],
      score: 0,
      shouldWrite: false,
      analysis: {},
      metadata: {
        createdAt: new Date().toISOString(),
        publishedAt,
        collector: '02-ingestion-pipeline',
        version: '0.2.0'
      }
    }
  };
});

return normalized;

// Remove duplicate records inside the current batch.
// URL is the preferred key; content is used when URL is unavailable.
const seen = new Set();
const unique = [];

for (const item of $input.all()) {
  const data = item.json;
  const key = data.url
    ? `url:${data.url.toLowerCase().replace(/\/$/, '')}`
    : `content:${data.content.toLowerCase().replace(/\s+/g, ' ').trim()}`;

  if (!key.endsWith(':') && !seen.has(key)) {
    seen.add(key);
    unique.push(item);
  }
}

return unique;

// Validate the minimum contract required by downstream workflows.
return $input.all().map((item) => {
  const data = item.json;
  const errors = [];

  if (!data.id) errors.push('id is required');
  if (!data.source) errors.push('source is required');
  if (!data.url) errors.push('url is required');
  if (!data.content) errors.push('content is required');
  if (!data.language) errors.push('language is required');

  if (errors.length) {
    throw new Error(`Invalid content item ${data.id || '(unknown)'}: ${errors.join('; ')}`);
  }

  return {
    json: {
      ...data,
      metadata: {
        ...data.metadata,
        status: 'normalized'
      }
    }
  };
});
